    vol_rounded = round(vol, 10)
    if vol_rounded == int(vol_rounded):
        lines.append(f"Volume: {int(vol_rounded)}")
    else:
        # Format with enough precision, then strip trailing zeros
        vol_str = f"{vol_rounded:.10f}".rstrip('0').rstrip('.')
        if '.' in vol_str:
            # Keep at most 2 decimal places by default (like examples)
            parts = vol_str.split('.')
            if len(parts[1]) > 2:
                vol_str = f"{vol_rounded:.2f}"
        lines.append(f"Volume: {vol_str}")
    lines.append("")
    lines.append("Recipe:")
    lines.append(f"Activity: {recipe['activity']}")
